\begin{align*}
\begin{vmatrix} 4 - \lambda & 1\\ -9 & -2 - \lambda \end{vmatrix} &= 0\\
(4 - \lambda)(-2 - \lambda) + 9 &= 0\\
\lambda^2 - 2\lambda + 1 &= 0\\
(\lambda - 1)^2 &= 0.
\end{align*}
Thus, \beig{\lambda = 1}{eq} is an eigenvalue and the matrix \beig{\mathbf{k}}{/eq} has only one eigenvalue. Hence, we turn to calculate \beig{\mathbf{K}}{/eq}.
\begin{align*}
\mathbf{K} &= \prod_{i=1}^k (\lambda_i - \mathbf{A})^k \vec{v}_i^k\\
&= (\lambda_1 - \mathbf{A})^{\dim V_{\lambda_1}} \mathbf{k}\\
\end{align*}
Hence, 
\begin{align*}
\mathbf{K} &= (1 - \mathbf{A})(1 - \mathbf{A})\mathbf{k}\\
&= (2 - 2A + A^2)\mathbf{k}\\
&= 2\mathbf{k} - 2A\mathbf{k} + \mathbf{k}\\
&= 3\mathbf{k} - 2A\mathbf{k}.
\end{align*}
Hence, 
\begin{align*}
\mathbf{K} &= 3\left(
\begin{pmatrix} 1 \\ -3 \end{pmatrix}, 
\begin{pmatrix} 0 \\ -2 \end{pmatrix}
\right) - 2\left(
\begin{pmatrix} 4 & 0 \\ -9 & -2 \end{pmatrix}
\right)
\left(
\begin{pmatrix} 1 \\ -3 \end{pmatrix}, 
\begin{pmatrix} 0 \\ -2 \end{pmatrix}
\right)\\
&= \left(
\begin{pmatrix} 3 \\ -9 \end{pmatrix}, 
\begin{pmatrix} 0 \\ -6 \end{pmatrix}
\right) - \left(
\begin{pmatrix} 18 \\ -18 \end{pmatrix}, 
\begin{pmatrix} 18 \\ -20 \end{pmatrix}
\right)\\
&= \left(
\begin{pmatrix} -15 \\ -9 \end{pmatrix}, 
\begin{pmatrix} -18 \\ 14 \end{pmatrix}
\right).
\end{align*}
Hence, \beig{\mathbf{A}^{100} = 3^{100}\mathbf{K}}{/eq}.{/eq}
The Answer is computed as $\mathbf{A}^{100} = 3^{100}$ times the vector $\left(
\begin{pmatrix} -15 \\ -9 \end{pmatrix}, 
